#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<vector<int>> a(6, vector<int>(6));
    for (int i = 0; i < 6; ++i) {
        for (int j = 0; j < 6; ++j) {
            cin >> a[i][j];
        }
    }

    int best = -9 * 7; // minimum possible sum: -9 * 7 = -63
    for (int i = 0; i <= 3; ++i) {
        for (int j = 0; j <= 3; ++j) {
            int sum = a[i][j] + a[i][j+1] + a[i][j+2]
                               + a[i+1][j+1]
                    + a[i+2][j] + a[i+2][j+1] + a[i+2][j+2];
            if (sum > best) best = sum;
        }
    }

    cout << best << '\n';
    return 0;
}
